-- Ken's Hardened V2 Fix

local b64_0xlll1l1 = {}
local char_0xIlIIlI='ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/'
for i_0xIll11I=1,#char_0xIlIIlI do b64_0xlll1l1[char_0xIlIIlI:sub(i_0xIll11I,i_0xIll11I)] = i_0xIll11I - 1 end

function b64_0xlll1l1.dec_0xIlIIII(d_0xlI1II1)
    d_0xlI1II1 = string.gsub(d_0xlI1II1, '[^'..char_0xIlIIlI..'=]', '')
    local r_0x11llI1 = {}
    for i_0xIll11I=1, #d_0xlI1II1, 4 do
        local c_0x1ll1Il = b64_0xlll1l1[d_0xlI1II1:sub(i_0xIll11I,i_0xIll11I)] or 0
        local c_0xll1lI1 = b64_0xlll1l1[d_0xlI1II1:sub(i_0xIll11I+1,i_0xIll11I+1)] or 0
        local c_0xIllI1I, c_0xI1I1lI = 0, 0
        local has3 = true
        local has4 = true
        local ch3 = d_0xlI1II1:sub(i_0xIll11I+2,i_0xIll11I+2)
        if ch3 == "=" then has3 = false else c_0xIllI1I = b64_0xlll1l1[ch3] or 0 end
        local ch4 = d_0xlI1II1:sub(i_0xIll11I+3,i_0xIll11I+3)
        if ch4 == "=" then has4 = false else c_0xI1I1lI = b64_0xlll1l1[ch4] or 0 end
        local b_0xl1I11l = c_0x1ll1Il * (2^18) + c_0xll1lI1 * (2^12) + c_0xIllI1I * (2^6) + c_0xI1I1lI
        local b_0xIllI1I = math.floor(b_0xl1I11l / (2^16)) % (2^8)
        local b_0xllIIl1 = math.floor(b_0xl1I11l / (2^8)) % (2^8)
        local b_0xl1Il1l = b_0xl1I11l % (2^8)
        table.insert(r_0x11llI1, string.char(b_0xIllI1I))
        if has3 then table.insert(r_0x11llI1, string.char(b_0xllIIl1)) end
        if has4 then table.insert(r_0x11llI1, string.char(b_0xl1Il1l)) end
    end
    return table.concat(r_0x11llI1)
end


local function bxor_0xlll1lI(a_0xlIIll1,b_0xIIIlIl)
    if bit32 then return bit32.bxor(a_0xlIIll1,b_0xIIIlIl) end
    local r_0xlllllI = 0
    for i_0xl1l1lI = 0, 7 do
        local x_0x1IllIl = a_0xlIIll1 % 2
        local y_0xI11lI1 = b_0xIIIlIl % 2
        if x_0x1IllIl ~= y_0xI11lI1 then r_0xlllllI = r_0xlllllI + (2^i_0xl1l1lI) end
        a_0xlIIll1 = math.floor(a_0xlIIll1 / 2)
        b_0xIIIlIl = math.floor(b_0xIIIlIl / 2)
    end
    return r_0xlllllI
end


local function bxor_str_0x1llIll(s_0xII1I1l, k_0xlIIlll)
    local r_0xll1llI = {}
    for i_0x1Il1lI=1, #s_0xII1I1l do
        local b_0x1III1I = string.byte(s_0xII1I1l, i_0x1Il1lI)
        local kb_0xIII1ll = string.byte(k_0xlIIlll, (i_0x1Il1lI-1) % #k_0xlIIlll + 1)
        r_0xll1llI[i_0x1Il1lI] = string.char(bxor_0xlll1lI(b_0x1III1I, kb_0xIII1ll))
    end
    return table.concat(r_0xll1llI)
end


local function getkeys_0xIIIIll()
    local seed = b64_0xlll1l1.dec_0xIlIIII("VnpRdFkwSWo=")
    local k1_enc = b64_0xlll1l1.dec_0xIlIIII("HEMAQRZ6JAA=")
    local k2_enc = b64_0xlll1l1.dec_0xIlIIII("F0xnPiBRPSk=")
    return bxor_str_0x1llIll(k1_enc, seed), bxor_str_0x1llIll(k2_enc, seed)
end


local function cff_0xIIIlII(a_0xIlIIlI)
    local st_0xl1l1II = 0
    local res_0xlIIIII = a_0xIlIIlI
    while true do
        if st_0xl1l1II == 0 then
            res_0xlIIIII = res_0xlIIIII + 1
            st_0xl1l1II = 1
        elseif st_0xl1l1II == 1 then
            res_0xlIIIII = res_0xlIIIII * 2
            st_0xl1l1II = 2
        elseif st_0xl1l1II == 2 then
            res_0xlIIIII = res_0xlIIIII - 3
            st_0xl1l1II = 3
        else
            break
        end
    end
    return res_0xlIIIII
end


local function chain_0xIIIllI(x) return x*2 end
local function chain_0xIllIll(x) return chain_0xIIIllI(x)+1 end


local d_0xIlI1lI = {
  {op=255, val="", is_enc=true},
}
local pc_0xll1I1l = 1
local stk_0xIIlIll = {}
stk_0xIIlIll._jmp = nil


local disp_0xIIII1I = {
    [0] = function() end,
    [1] = function(s, v) table.insert(s, v) end,
    [2] = function(s, v) table.insert(s, _G[v]) end,
    [3] = function(s, v) local val=table.remove(s); _G[v]=val end,
    [4] = function(s, _) table.insert(s, {}) end,
    [5] = function(s, _) local val=table.remove(s); local key=table.remove(s); local t=table.remove(s); t[key]=val; table.insert(s, t) end,
    [16] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a+b) end,
    [17] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a-b) end,
    [18] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a*b) end,
    [19] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a/b) end,
    [32] = function(s, n) 
        local args = {}
        for i=1,tonumber(n) do table.insert(args, 1, table.remove(s)) end
        local f = table.remove(s)
        if type(f) == "function" then
            local result = {f(unpack(args))}
            for _,v in ipairs(result) do table.insert(s, v) end
        else
            print("[LBI] Not a function: "..tostring(f))
        end
    end,
    [33] = function(s) return table.remove(s) end,
    [48] = function(s, offset) 
        local cond = table.remove(s)
        if not cond then 
            s._jmp = tonumber(offset)
        end
    end,
    [49] = function(s, offset)
        s._jmp = tonumber(offset)
    end,
    [255] = function(s, v)
        local fn, err = loadstring(v)
        if not fn then
            print("[LBI] Load error: "..tostring(err))
        else
            local ok, res = pcall(fn)
            if not ok then print("[LBI] Run error: "..tostring(res)) end
        end
    end
}



local k1, k2 = getkeys_0xIIIIll()

local state_0xlIlII1 = 0
while true do
    if state_0xlIlII1 == 0 then  -- FETCH
        if pc_0xll1I1l > #d_0xIlI1lI then break end
        local inst = d_0xIlI1lI[pc_0xll1I1l]
        local opcode = inst.op
        local val = inst.val
        if inst.is_enc then
            local d = b64_0xlll1l1.dec_0xIlIIII(val)
            d = bxor_str_0x1llIll(d, k2)
            val = bxor_str_0x1llIll(d, k1)
        end
        stk_0xIIlIll._jmp = nil
        pc_0xll1I1l = pc_0xll1I1l + 1
        cur_op_0xII1llI = opcode
        cur_val_0xIlIl1I = val
        state_0xlIlII1 = 1

    elseif state_0xlIlII1 == 1 then  -- EXECUTE
        local handler = disp_0xIIII1I[cur_op_0xII1llI]
        if handler then
            handler(stk_0xIIlIll, cur_val_0xIlIl1I)
        end
        if stk_0xIIlIll._jmp then
            pc_0xll1I1l = pc_0xll1I1l + stk_0xIIlIll._jmp
        end
        state_0xlIlII1 = 0
    else
        break
    end
end
